import { useState, useMemo } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { regions, channelMap, type Channel } from "./data/channels";
import FeedCell from "./components/FeedCell";

const GRID_SIZE = 4; // 2x2

export default function App() {
  const [activeRegion, setActiveRegion] = useState("me");
  const [pageMap, setPageMap] = useState<Record<string, number>>({});

  const region = regions.find((r) => r.key === activeRegion) ?? regions[0];

  // Resolve channels for current region, filter to those with playable streams first
  const allRegionChannels = useMemo(() => {
    return region.channelIds
      .map((id) => channelMap.get(id))
      .filter(Boolean) as Channel[];
  }, [region]);

  // Sort: channels with fallbackVideoId or hlsUrl first
  const sortedChannels = useMemo(() => {
    return [...allRegionChannels].sort((a, b) => {
      const aPlayable = a.fallbackVideoId || a.hlsUrl ? 1 : 0;
      const bPlayable = b.fallbackVideoId || b.hlsUrl ? 1 : 0;
      return bPlayable - aPlayable;
    });
  }, [allRegionChannels]);

  const currentPage = pageMap[activeRegion] ?? 0;
  const totalPages = Math.max(1, Math.ceil(sortedChannels.length / GRID_SIZE));
  const pageChannels = sortedChannels.slice(
    currentPage * GRID_SIZE,
    currentPage * GRID_SIZE + GRID_SIZE
  );

  const setPage = (page: number) => {
    setPageMap((prev) => ({ ...prev, [activeRegion]: page }));
  };

  const playableCount = sortedChannels.filter(
    (c) => c.fallbackVideoId || c.hlsUrl
  ).length;

  return (
    <div className="w-full h-full flex flex-col overflow-hidden bg-zinc-950">
      {/* Region Tabs */}
      <div className="flex-none flex items-center gap-0.5 px-2 pt-2 pb-1 overflow-x-auto scrollbar-none">
        {regions.map((r) => {
          const isActive = r.key === activeRegion;
          const count = r.channelIds.length;
          return (
            <button
              key={r.key}
              onClick={() => setActiveRegion(r.key)}
              className={`
                flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-medium whitespace-nowrap transition-all
                border-b-2
                ${
                  isActive
                    ? "border-blue-500 text-white bg-zinc-800/60"
                    : "border-transparent text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800/30"
                }
              `}
            >
              <span>{r.emoji}</span>
              <span>{r.label}</span>
              <span
                className={`ml-0.5 px-1.5 py-0.5 text-[9px] rounded-full ${
                  isActive
                    ? "bg-blue-500/20 text-blue-400"
                    : "bg-zinc-800 text-zinc-500"
                }`}
              >
                {count}
              </span>
            </button>
          );
        })}
      </div>

      {/* Info bar */}
      <div className="flex-none flex items-center justify-between px-3 py-1 text-[10px] text-zinc-500 border-b border-zinc-800/50">
        <span>
          {playableCount}/{sortedChannels.length} streams available
        </span>
        {totalPages > 1 && (
          <div className="flex items-center gap-2">
            <button
              onClick={() => setPage(Math.max(0, currentPage - 1))}
              disabled={currentPage === 0}
              className="p-0.5 hover:text-zinc-300 disabled:opacity-30 disabled:cursor-not-allowed"
            >
              <ChevronLeft size={14} />
            </button>
            <div className="flex items-center gap-1">
              {Array.from({ length: totalPages }, (_, i) => (
                <button
                  key={i}
                  onClick={() => setPage(i)}
                  className={`w-1.5 h-1.5 rounded-full transition-colors ${
                    i === currentPage ? "bg-blue-500" : "bg-zinc-700 hover:bg-zinc-500"
                  }`}
                />
              ))}
            </div>
            <span className="text-zinc-600 tabular-nums">
              {currentPage + 1}/{totalPages}
            </span>
            <button
              onClick={() => setPage(Math.min(totalPages - 1, currentPage + 1))}
              disabled={currentPage >= totalPages - 1}
              className="p-0.5 hover:text-zinc-300 disabled:opacity-30 disabled:cursor-not-allowed"
            >
              <ChevronRight size={14} />
            </button>
          </div>
        )}
      </div>

      {/* 2Ãƒâ€”2 Grid */}
      <div className="flex-1 min-h-0 grid grid-cols-2 grid-rows-2 gap-px bg-zinc-800/50 p-px">
        {[0, 1, 2, 3].map((i) => {
          const channel = pageChannels[i];
          if (!channel) {
            return (
              <div
                key={`empty-${i}`}
                className="bg-zinc-900/50 flex items-center justify-center"
              >
                <span className="text-zinc-700 text-xs">Ã¢â‚¬â€</span>
              </div>
            );
          }
          return <FeedCell key={`${channel.id}-${currentPage}`} channel={channel} />;
        })}
      </div>
    </div>
  );
}

