import { useState, useEffect, useCallback } from "react";
import { formatDistanceToNow } from "date-fns";
import { RefreshCw, Play, ExternalLink, Youtube, Eye, User } from "lucide-react";

interface VideoItem {
  id: string;
  title: string;
  link: string;
  published: string;
  channel: string;
  channelUrl: string;
  thumbnail: string;
}

const CHANNELS = [
  { id: "UCBVjMGOIkavEAhyqpxJ73Dw", name: "WION" },
  { id: "UCef1-8eOpJgud7szVPlZQAQ", name: "Task & Purpose" },
  { id: "UCAHPsa4SWLlAZFhgcnPfMIg", name: "CaspianReport" },
  { id: "UCwnKziETDbHJtx78nIkfYug", name: "Military History" },
  { id: "UCFWjEwhX6cSAKBQ28pufG3w", name: "VisualPolitik" },
  { id: "UCXL0O0bGGakmKjkPwc3o0gQ", name: "DW News" },
  { id: "UC16niRr50-MSBwiO3YDb3RA", name: "BBC News" },
  { id: "UChqUTb7kYRX8-EiaN3XFrSQ", name: "Reuters" },
];

const PROXY = "/api/proxy?url=";

function parseYouTubeRSS(xml: string, channelName: string): VideoItem[] {
  const parser = new DOMParser();
  const doc = parser.parseFromString(xml, "text/xml");
  const entries = doc.getElementsByTagName("entry");
  const results: VideoItem[] = [];
  for (let i = 0; i < Math.min(entries.length, 5); i++) {
    const entry = entries[i];
    const id = entry.getElementsByTagName("yt:videoId")[0]?.textContent || "";
    const title = entry.getElementsByTagName("title")[0]?.textContent || "";
    const link = entry.getElementsByTagName("link")[0]?.getAttribute("href") || "";
    const published = entry.getElementsByTagName("published")[0]?.textContent || "";
    const channelEl = entry.getElementsByTagName("author")[0];
    const channel = channelEl?.getElementsByTagName("name")[0]?.textContent || channelName;
    const channelUrl = channelEl?.getElementsByTagName("uri")[0]?.textContent || "";
    results.push({ id, title, link, published, channel, channelUrl, thumbnail: `https://i.ytimg.com/vi/${id}/mqdefault.jpg` });
  }
  return results;
}

export default function App() {
  const [videos, setVideos] = useState<VideoItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [channelFilter, setChannelFilter] = useState("All");

  const fetchFeeds = useCallback(async () => {
    setLoading(true);
    const allVideos: VideoItem[] = [];
    await Promise.allSettled(
      CHANNELS.map(async (ch) => {
        try {
          const res = await fetch(PROXY + encodeURIComponent(`https://www.youtube.com/feeds/videos.xml?channel_id=${ch.id}`));
          const text = await res.text();
          allVideos.push(...parseYouTubeRSS(text, ch.name));
        } catch {}
      })
    );
    allVideos.sort((a, b) => new Date(b.published).getTime() - new Date(a.published).getTime());
    setVideos(allVideos);
    setLoading(false);
  }, []);

  useEffect(() => { fetchFeeds(); const i = setInterval(fetchFeeds, 300000); return () => clearInterval(i); }, [fetchFeeds]);

  const filtered = channelFilter === "All" ? videos : videos.filter(v => v.channel === channelFilter);
  const uniqueChannels = [...new Set(videos.map(v => v.channel))];

  return (
    <div className="h-full flex flex-col bg-zinc-950 text-zinc-100">
      <div className="flex items-center gap-2 px-3 py-2 border-b border-zinc-800">
        <Youtube className="w-4 h-4 text-red-500 shrink-0" />
        <span className="text-xs font-medium text-zinc-300 flex-1">OSINT Channels</span>
        <span className="text-[10px] text-zinc-600">{filtered.length} videos</span>
        <button onClick={fetchFeeds} className="p-1 hover:bg-zinc-800 rounded">
          <RefreshCw className={`w-3.5 h-3.5 text-zinc-400 ${loading ? "animate-spin" : ""}`} />
        </button>
      </div>
      <div className="flex gap-1 px-3 py-1.5 overflow-x-auto border-b border-zinc-800/50">
        <button onClick={() => setChannelFilter("All")} className={`px-2 py-0.5 rounded text-[10px] font-medium whitespace-nowrap transition-colors ${channelFilter === "All" ? "bg-zinc-100 text-zinc-900" : "bg-zinc-800/50 text-zinc-500 hover:text-zinc-300"}`}>All</button>
        {uniqueChannels.map((ch) => (
          <button key={ch} onClick={() => setChannelFilter(ch)} className={`px-2 py-0.5 rounded text-[10px] font-medium whitespace-nowrap transition-colors ${channelFilter === ch ? "bg-red-500/20 text-red-400" : "bg-zinc-800/50 text-zinc-500 hover:text-zinc-300"}`}>{ch}</button>
        ))}
      </div>
      <div className="flex-1 overflow-y-auto">
        {loading && videos.length === 0 ? (
          <div className="flex items-center justify-center h-32 text-zinc-500 text-xs">Loading feeds...</div>
        ) : (
          <div className="divide-y divide-zinc-800/50">
            {filtered.map((video) => (
              <a key={video.id} href={video.link} target="_blank" rel="noopener noreferrer" className="flex gap-2.5 px-3 py-2 hover:bg-zinc-900/50 transition-colors group">
                <div className="relative w-28 h-16 rounded overflow-hidden bg-zinc-800 shrink-0">
                  <img src={video.thumbnail} alt="" className="w-full h-full object-cover" loading="lazy" />
                  <div className="absolute inset-0 flex items-center justify-center bg-black/30 opacity-0 group-hover:opacity-100 transition-opacity">
                    <Play className="w-5 h-5 text-white fill-white" />
                  </div>
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-xs text-zinc-200 leading-snug line-clamp-2 group-hover:text-white">{video.title}</p>
                  <div className="flex items-center gap-2 mt-1">
                    <span className="text-[10px] text-red-400 font-medium">{video.channel}</span>
                    <span className="text-[10px] text-zinc-600">{formatDistanceToNow(new Date(video.published), { addSuffix: true })}</span>
                  </div>
                </div>
              </a>
            ))}
          </div>
        )}
      </div>
      <div className="px-3 py-1 border-t border-zinc-800 text-[10px] text-zinc-600 flex justify-between">
        <span>{CHANNELS.length} channels monitored</span>
        <span>Auto-refresh 5min</span>
      </div>
    </div>
  );
}
